   149→/// Get steeplechase entries for a heat (library function)
   150→pub fn get_entries(args: &ReinArgs) -> Result<Vec<SteeplechaseEntry>, String> {
   151→    let firemark = Firemark::parse(&args.firemark)
   152→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   153→
   154→    let firemark_raw = firemark.as_str();
   155→
   156→    // Build the grep pattern for git log
   157→    // Pattern matches both heat-level (₣XX) and pace-level (₢XX...) entries
   158→    // Filter by identity, not brand: jjb:*:₣XX or jjb:*:₢XX
   159→    let grep_pattern = format!(
   160→        "^jjb:[^:]+:({}{}|{}{})",
   161→        FIREMARK_PREFIX, firemark_raw,
   162→        CORONET_PREFIX, firemark_raw
   163→    );
   164→
   165→    let output = Command::new("git")
   166→        .args([
   167→            "log",
   168→            "--all",
   169→            "--extended-regexp",
   170→            &format!("--grep={}", grep_pattern),
   171→            "--format=%ai\t%s",
   172→        ])
   173→        .output()
   174→        .map_err(|e| format!("Failed to run git log: {}", e))?;
   175→
   176→    if !output.status.success() {
   177→        let stderr = String::from_utf8_lossy(&output.stderr);
   178→        return Err(format!("git log failed: {}", stderr));
   179→    }
   180→
   181→    let stdout = String::from_utf8_lossy(&output.stdout);
   182→
   183→    let entries: Vec<SteeplechaseEntry> = stdout
   184→        .lines()
   185→        .filter_map(|line| parse_log_line(line, firemark_raw))
   186→        .take(args.limit)
   187→        .collect();
   188→
   189→    Ok(entries)
   190→}
