    let (identity, rest) = if after_brand.starts_with(CORONET_PREFIX) {
        // Coronet: ₢XXXXX (1 prefix char + 5 base64 chars = 6 chars total in UTF-8)
        let coronet_end = CORONET_PREFIX.len_utf8() + 5;
