/// Parse a single git log line into a SteeplechaseEntry
/// Line format: "YYYY-MM-DD HH:MM:SS -ZZZZ<TAB>subject"
fn parse_log_line(line: &str, firemark_raw: &str) -> Option<SteeplechaseEntry> {
