    let timestamp = parse_timestamp(parts[0]);
    let subject = parts[1];

    // Try parsing new format
    if let Some(mut entry) = parse_new_format(subject, firemark_raw) {
        entry.timestamp = timestamp;
        return Some(entry);
    }

    None
