        .collect();

    Ok(entries)
}

/// Run jjx_rein command (CLI wrapper)
pub fn run(args: ReinArgs) -> i32 {
    match get_entries(&args) {
        Ok(entries) => {
            match serde_json::to_string_pretty(&entries) {
                Ok(json) => {
                    println!("{}", json);
